@st.cache_resource(show_spinner=False)
def _warm_model():
    """Pre-load phi3:mini into memory once per server process so the first real
    report doesn't wait for the model to load (Ollama unloads after idle)."""
    try:
        ollama.chat(
            model=MODEL_NAME,
            messages=[{"role": "user", "content": "ready"}],
            options={"num_predict": 1},
            keep_alive="30m",
        )
    except Exception:
        pass
    return True


_warm_model()

