def _logo_dev_token() -> str:
    """Optional logo.dev publishable token (better-quality logos for any of
    50M+ companies). Without it the code falls back to a key-free favicon
    service so logos still work. Configure in .streamlit/secrets.toml:
        [company]
        logo_dev_token = "pk_xxxxxxxx"
    """
    try:
        return str(st.secrets["company"]["logo_dev_token"]).strip()
    except Exception:
        return ""


def _clean_domain(domain: str) -> str:
    d = (domain or "").strip().lower()
    d = re.sub(r"^https?://", "", d)
    d = d.split("/")[0].strip()
    return d


def _domain_guess(name: str) -> str:
    """Crude domain guess from a company name, used only for the key-free
    favicon fallback (e.g. 'Acme Global Corp' -> 'acmeglobalcorp.com')."""
    slug = re.sub(r"[^a-z0-9]", "", (name or "").lower())
    return f"{slug}.com" if slug else ""


def company_logo_url(name: str, domain: str = "") -> str:
    """Resolve a logo image URL for an organization.
    Priority: explicit domain > company name. Uses logo.dev when a token is
    configured (covers any company by name or domain), otherwise a key-free
    Google favicon service. Returns '' if nothing usable is provided."""
    token = _logo_dev_token()
    domain = _clean_domain(domain)
    if domain and "." in domain:
        if token:
            return f"https://img.logo.dev/{domain}?token={token}&size=512&format=png&retina=true"
        return f"https://www.google.com/s2/favicons?domain={domain}&sz=256"
    name = (name or "").strip()
    if name:
        if token:
            return f"https://img.logo.dev/name/{urllib.parse.quote(name)}?token={token}&size=512&format=png&retina=true"
        guess = _domain_guess(name)
        if guess:
            return f"https://www.google.com/s2/favicons?domain={guess}&sz=256"
    return ""


@st.cache_data(show_spinner=False)
def fetch_logo_bytes(url: str):
    """Download a logo image and return raw bytes (for embedding in the PDF).
    Returns None on any failure so the PDF still builds without a logo."""
    if not url:
        return None
    try:
        req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0 DOMINATE3AI"})
        with urllib.request.urlopen(req, timeout=12) as resp:
            data = resp.read()
        return data if data else None
    except Exception:
        return None


def extract_document_text(uploaded_file) -> str:
    """Extract plain text from an uploaded consulting document.
    Supports .txt/.md (native), .pdf (pypdf), and .docx (python-docx).
    Returns a human-readable error string if a parser isn't installed."""
    name = (getattr(uploaded_file, "name", "") or "").lower()
    try:
        raw = uploaded_file.getvalue()
    except Exception:
        try:
            raw = uploaded_file.read()
        except Exception:
            return ""

    if name.endswith((".txt", ".md")):
        return raw.decode("utf-8", errors="ignore")

    if name.endswith(".pdf"):
        try:
            from pypdf import PdfReader
        except Exception:
            return "[Could not read PDF: install pypdf  ->  pip install pypdf]"
        try:
            reader = PdfReader(io.BytesIO(raw))
            return "\n".join((p.extract_text() or "") for p in reader.pages).strip()
        except Exception as e:
            return f"[Could not read PDF: {e}]"

    if name.endswith(".docx"):
        try:
            import docx  # python-docx
        except Exception:
            return "[Could not read DOCX: install python-docx  ->  pip install python-docx]"
        try:
            d = docx.Document(io.BytesIO(raw))
            return "\n".join(p.text for p in d.paragraphs).strip()
        except Exception as e:
            return f"[Could not read DOCX: {e}]"

    return "[Unsupported file type — use PDF, DOCX, TXT, or MD.]"


