# ── Ollama generation ─────────────────────────────────────────────────────────
@st.cache_data(show_spinner=False)
def generate_section_report(prompt: str, sections: tuple, depth: str, max_tokens: int) -> str:
    """Ask phi3:mini to write one report covering the given sections."""
    if ollama is None:
        return "## Error\nError generating report: ollama package is not installed."

    section_list = "\n".join(f"- {s}" for s in sections)
    full_prompt = (
        f"{prompt}\n\n"
        f"Write a professional business report with EXACTLY these sections, in this order:\n"
        f"{section_list}\n\n"
        f"FORMAT RULES (follow strictly):\n"
        f"1. Begin each section with a heading line starting with '## ' followed by the section name.\n"
        f"2. Under each heading, write 3 to 5 bullet points. Start every bullet with '- '.\n"
        f"3. Each bullet MUST begin with a short bold sub-heading in the form "
        f"'**Sub-heading:**' (2-5 words) followed by a concrete 1-2 sentence explanation.\n"
        f"4. Be specific and concrete: cite numbers, percentages, timeframes, or named "
        f"levers wherever possible. Do NOT write vague, generic, or ambiguous statements.\n"
        f"5. No filler, no repetition, no preamble before the first heading.\n"
        f"Keep each section {depth}.\n\nREPORT:\n"
    )
    try:
        response = ollama.chat(
            model=MODEL_NAME,
            messages=[{"role": "user", "content": full_prompt}],
            options={"num_predict": max_tokens, "temperature": 0.4},
            keep_alive="30m",          # keep the model loaded so later reports are fast
        )
        return response["message"]["content"]
    except Exception as e:
        return f"## Error\nError generating report: {e}"


def parse_sections(raw_text: str, expected_sections: list) -> list:
    """Split a '## Heading' formatted report into [{heading, content}, ...]."""
    parts = re.split(r"^##\s*", raw_text, flags=re.MULTILINE)
    parsed = []
    for part in parts:
        part = part.strip()
        if not part:
            continue
        lines = part.split("\n", 1)
        heading = lines[0].strip().lstrip("#").strip()
        content = lines[1].strip() if len(lines) > 1 else ""
        if heading:
            parsed.append({"heading": heading, "content": content})

    # Fallback if the model didn't use '##' headings: show everything in section 1
    if not parsed:
        parsed = [{"heading": expected_sections[0], "content": raw_text.strip()}]
    return parsed


def qml_metrics(org: str) -> tuple:
    """Deterministic pseudo-QML score/ROI, stable per organization name."""
    seed = sum(ord(c) for c in org) if org else 42
    score = 92 + (seed % 8)               # 92–99
    roi_low = 220 + (seed % 80)           # 220–299
    roi_high = roi_low + 120
    return f"{score}.{seed % 9}", f"{roi_low}–{roi_high}%"


# ── Rendering ─────────────────────────────────────────────────────────────────
def _format_bullets_html(content: str) -> str:
    """Turn '- **Heading:** explanation' lines into a styled bullet list.
    Falls back to plain pre-wrapped text if no bullets are present."""
    import html as _html
    lines = [ln.rstrip() for ln in (content or "").split("\n")]
    intro, items = [], []
    for ln in lines:
        s = ln.strip()
        if not s:
            continue
        m = re.match(r"^[-*•]\s+(.*)$", s)
        if m:
            items.append(m.group(1).strip())
        elif items:
            items[-1] += " " + s          # continuation of the previous bullet
        else:
            intro.append(s)

    def fmt(t: str) -> str:
        t = _html.escape(t)
        t = re.sub(r"\*\*(.+?)\*\*", r"<strong>\1</strong>", t)     # **bold**
        if "<strong>" not in t:                                     # bold a "Heading:" lead-in
            t = re.sub(r"^([^:]{2,60}):\s", r"<strong>\1:</strong> ", t)
        return t

    html_parts = []
    if intro:
        html_parts.append('<div class="rb-content">' + "<br>".join(fmt(x) for x in intro) + "</div>")
    if items:
        html_parts.append('<ul class="rb-bullets">' + "".join(f"<li>{fmt(it)}</li>" for it in items) + "</ul>")
    if not html_parts:
        html_parts.append('<div class="rb-content">' + fmt(content or "") + "</div>")
    return "".join(html_parts)


def render_report(report: dict, rtype: str) -> None:
    import html as _html  # escape model output so stray <,>,& can't break layout

    css_class = f"rb-{rtype}"
    labels = {
        "normal":    ("📊", "NORMAL REPORT",   "PDF"),
        "advanced":  ("🔬", "ADVANCED REPORT", "PDF"),
        "monetized": ("⚛",  "MONETIZED — QML", "QML"),
    }
    icon, badge_text, badge_tag = labels[rtype]
    title = _html.escape(report.get("title", f"{rtype.title()} Report"))

    # Build as ONE single line — no leading spaces, no newlines — so Streamlit's
    # markdown parser never treats any line as an indented code block.
    parts = [
        f'<div class="report-box {css_class}">',
        '<div class="rb-header">',
        f'<span style="font-size:1.2rem">{icon}</span>',
        f'<div class="rb-badge">{badge_text}</div>',
        f'<div class="rb-title">{title}</div>',
        f'<div style="margin-left:auto"><span class="rb-badge">{badge_tag}</span></div>',
        '</div>',
        '<div class="rb-body">',
    ]

    if rtype == "monetized":
        score = _html.escape(str(report.get("qml_score", "97.4")))
        roi = _html.escape(str(report.get("projected_roi", "280–420%")))
        parts.append(
            '<div class="qml-score-box">'
            f'<div><div class="qml-val">{score}%</div><div class="qml-lbl">QML Score</div></div>'
            f'<div><div class="qml-val">{roi}</div><div class="qml-lbl">Projected ROI</div></div>'
            '</div>'
        )

    for sec in report.get("sections", []):
        heading = _html.escape(sec.get("heading", ""))
        parts.append(f'<div class="rb-section-title">{heading}</div>')
        parts.append(_format_bullets_html(sec.get("content", "")))

    parts.append('</div></div>')
    st.markdown("".join(parts), unsafe_allow_html=True)


def build_text_export(reports: dict, org: str) -> str:
    lines = [
        "=" * 70,
        "DOMINATE 3AI — Intelligence Reports",
        f"Organization: {org}",
        f"Generated: {datetime.now().strftime('%Y-%m-%d %H:%M')}",
        f"Model: Ollama {MODEL_NAME} (local)",
        "Powered by ABP Communications LLC | abpcommunications.com",
        "=" * 70,
    ]
    for rtype in ["normal", "advanced", "monetized"]:
        if rtype not in reports:
            continue
        report = reports[rtype]
        lines += ["", "-" * 70, report.get("title", rtype.upper()), "-" * 70]
        if rtype == "monetized":
            lines.append(f"QML Score: {report.get('qml_score','—')}%  |  Projected ROI: {report.get('projected_roi','—')}")
        for sec in report.get("sections", []):
            lines += ["", f">> {sec.get('heading','').upper()}", sec.get("content", "")]
    lines += ["", "=" * 70, "(c) 2025 ABP Communications LLC · DOMINATE 3AI · Hartford, CT 06114"]
    return "\n".join(lines)


def build_pdf(reports: dict, org: str, logo_url: str = ""):
    """Branded multi-page PDF: cover page + Table of Contents + per-report pages,
    with a running header band on every content page. Section bodies render as
    bullet points. Returns PDF bytes, or None if reportlab isn't installed (the
    caller then falls back to the plain-text attachment).
    Install with:  pip install reportlab
    """
    try:
        from reportlab.lib.pagesizes import LETTER
        from reportlab.lib.units import inch
        from reportlab.lib import colors
        from reportlab.lib.styles import ParagraphStyle
        from reportlab.lib.enums import TA_LEFT
        from reportlab.platypus import (SimpleDocTemplate, Paragraph, Spacer,
                                        PageBreak, Table, TableStyle)
        from reportlab.platypus.flowables import HRFlowable
        from reportlab.platypus.tableofcontents import TableOfContents
        from reportlab.lib.utils import ImageReader
    except Exception:
        return None

    import io as _io, os as _os, html as _h

    NAVY = colors.HexColor("#0A1628")
    GOLD = colors.HexColor("#C8960C")
    INK = colors.HexColor("#1c2733")
    MUTE = colors.HexColor("#6B7A8A")
    LAV_BG = colors.HexColor("#F1ECFB")
    LAV_BD = colors.HexColor("#8B5CF6")
    SEPLINE = colors.HexColor("#33425A")
    _dash = "\u2014"

    REPORT_LABELS = {"normal": "Normal Report", "advanced": "Advanced Report",
                     "monetized": "Monetized Report (Quantum ML)"}

    def esc(t):
        return _h.escape(str(t or "")).replace("\n", "<br/>")

    # Subtitle / report-type line (mirrors the cover of the reference layout).
    _present = [r for r in ["normal", "advanced", "monetized"] if r in reports]
    if len(_present) == 3:
        subtitle = "Complete Intelligence Suite (Normal, Advanced, Monetized)"
    else:
        subtitle = "Intelligence Report: " + ", ".join(
            REPORT_LABELS[r].split(" (")[0] for r in _present)

    S = {
        "cover_eyebrow": ParagraphStyle("ce", fontName="Helvetica-Bold", fontSize=13,
                                        textColor=GOLD, leading=15, alignment=TA_LEFT),
        "cover_title": ParagraphStyle("ct", fontName="Helvetica-Bold", fontSize=30,
                                      textColor=colors.white, leading=34, alignment=TA_LEFT),
        "cover_sub": ParagraphStyle("cs", fontName="Helvetica", fontSize=12.5,
                                    textColor=GOLD, leading=17, alignment=TA_LEFT),
        "toc_h": ParagraphStyle("th", fontName="Helvetica-Bold", fontSize=22,
                                textColor=NAVY, leading=26),
        "group": ParagraphStyle("D3Group", fontName="Helvetica-Bold", fontSize=22,
                                textColor=NAVY, leading=26, spaceBefore=2, spaceAfter=2),
        "sec": ParagraphStyle("D3Sec", fontName="Helvetica-Bold", fontSize=13,
                              textColor=GOLD, leading=16, spaceBefore=13, spaceAfter=3),
        "body": ParagraphStyle("body", fontName="Helvetica", fontSize=10,
                               textColor=INK, leading=15, alignment=TA_LEFT, spaceAfter=6),
        "bullet": ParagraphStyle("bullet", fontName="Helvetica", fontSize=10,
                                 textColor=INK, leading=14.5, alignment=TA_LEFT,
                                 leftIndent=16, bulletIndent=3, spaceAfter=5),
        "kpi": ParagraphStyle("kpi", fontName="Helvetica-Bold", fontSize=9,
                              textColor=LAV_BD, leading=12),
    }

    here = _os.path.dirname(_os.path.abspath(__file__))
    brand_logo = None
    for _fn in ("abp_logo.png", auth.LOGO_FILENAME):
        _p = _os.path.join(here, _fn)
        if _os.path.exists(_p):
            brand_logo = _p
            break

    comp_logo_bytes = fetch_logo_bytes(logo_url) if logo_url else None

    class _D3Doc(SimpleDocTemplate):
        """Feeds heading flowables to the TableOfContents for page numbers."""
        def afterFlowable(self, flowable):
            if isinstance(flowable, Paragraph):
                sname = flowable.style.name
                txt = flowable.getPlainText()
                if sname == "D3Group":
                    self.notify("TOCEntry", (0, txt, self.page))
                elif sname == "D3Sec":
                    self.notify("TOCEntry", (1, txt, self.page))

    # ── cover page (drawn directly on the canvas) ────────────────────────────
    def _cover(c, doc):
        W, H = LETTER
        ML = 0.9 * inch
        cw = W - 2 * ML
        c.saveState()
        c.setFillColor(NAVY); c.rect(0, 0, W, H, fill=1, stroke=0)
        c.setFillColor(GOLD); c.rect(0, H - 16, W, 16, fill=1, stroke=0)
        if brand_logo:
            try:
                ir = ImageReader(brand_logo); iw, ih = ir.getSize()
                lw = 1.15 * inch; lh = lw * ih / float(iw)
                c.drawImage(ir, W - ML - lw, H - 0.55 * inch - lh, lw, lh,
                            preserveAspectRatio=True, mask="auto")
            except Exception:
                pass

        def dp(text, style, y_top):
            p = Paragraph(text, style)
            _pw, _ph = p.wrap(cw, 2000)
            p.drawOn(c, ML, y_top - _ph)
            return y_top - _ph

        y = H - 2.85 * inch
        y = dp("INTELLIGENCE REPORT", S["cover_eyebrow"], y)
        c.setFillColor(GOLD); c.rect(ML, y - 9, 1.0 * inch, 3, fill=1, stroke=0)
        y = dp(esc(org), S["cover_title"], y - 22)
        y = dp(esc(subtitle), S["cover_sub"], y - 8)

        # Organization logo — appears right after the org name/subtitle, rendered
        # at high resolution so it stays sharp (see company_logo_url sizing).
        if comp_logo_bytes:
            try:
                cir = ImageReader(_io.BytesIO(comp_logo_bytes)); ciw, cih = cir.getSize()
                clh = 0.72 * inch; clw = clh * ciw / float(cih)
                if clw > 2.4 * inch:
                    clw = 2.4 * inch; clh = clw * cih / float(ciw)
                c.drawImage(cir, ML, y - 0.22 * inch - clh, clw, clh,
                            preserveAspectRatio=True, mask="auto")
            except Exception:
                pass

        rows = [("REPORT TYPE", subtitle),
                ("GENERATED ON", datetime.now().strftime("%B %d, %Y at %I:%M %p")),
                ("GENERATED BY", "DOMINATE 3AI \u2014 ABP Communications LLC"),
                ("DATE", datetime.now().strftime("%Y-%m-%d"))]
        my = H - 5.5 * inch
        for lbl, val in rows:
            c.setFont("Helvetica-Bold", 9); c.setFillColor(GOLD)
            c.drawString(ML, my, lbl)
            c.setFont("Helvetica", 11); c.setFillColor(colors.white)
            c.drawString(ML + 1.75 * inch, my, str(val)[:80])
            c.setStrokeColor(SEPLINE); c.setLineWidth(0.5)
            c.line(ML, my - 9, W - ML, my - 9)
            my -= 0.46 * inch

        c.setFont("Helvetica-Bold", 12); c.setFillColor(GOLD)
        c.drawString(ML, 0.72 * inch, "DOMINATE 3AI")
        c.setFont("Helvetica", 8); c.setFillColor(colors.HexColor("#8595A6"))
        c.drawString(ML, 0.55 * inch,
                     "Powered by ABP Communications LLC  -  abpcommunications.com  -  Hartford, CT")
        c.restoreState()

    # ── header band + footer on every content/TOC page ───────────────────────
    def _content(c, doc):
        W, H = LETTER
        ML = 0.85 * inch
        c.saveState()
        bandH = 0.92 * inch
        c.setFillColor(NAVY); c.rect(0, H - bandH, W, bandH, fill=1, stroke=0)
        c.setFillColor(colors.white); c.setFont("Helvetica-Bold", 12)
        c.drawString(ML, H - 0.5 * inch, str(org)[:60])
        c.setFillColor(GOLD); c.setFont("Helvetica", 8)
        c.drawString(ML, H - 0.68 * inch, "DOMINATE 3AI Intelligence Report")
        if brand_logo:
            try:
                ir = ImageReader(brand_logo); iw, ih = ir.getSize()
                lh = 0.5 * inch; lw = lh * iw / float(ih)
                c.drawImage(ir, W - ML - lw, H - 0.5 * inch - lh / 2 - 0.06 * inch, lw, lh,
                            preserveAspectRatio=True, mask="auto")
            except Exception:
                pass
        c.setStrokeColor(GOLD); c.setLineWidth(1)
        c.line(0, H - bandH, W, H - bandH)
        c.setStrokeColor(colors.HexColor("#D8DEE6")); c.setLineWidth(0.5)
        c.line(ML, 0.72 * inch, W - ML, 0.72 * inch)
        c.setFont("Helvetica", 8); c.setFillColor(MUTE)
        c.drawString(ML, 0.56 * inch, "\u00a9 2026 ABP Communications LLC - Confidential")
        c.drawCentredString(W / 2.0, 0.56 * inch, "DOMINATE 3AI")
        c.drawRightString(W - ML, 0.56 * inch, "Page %d" % doc.page)
        c.restoreState()

    def _section_flowables(content):
        out, emitted = [], False
        for ln in (content or "").split("\n"):
            s = ln.strip()
            if not s:
                continue
            m = re.match(r"^[-*\u2022]\s+(.*)$", s)
            txt = (m.group(1).strip() if m else s)
            txt = _h.escape(txt)
            txt = re.sub(r"\*\*(.+?)\*\*", r"<b>\1</b>", txt)
            if "<b>" not in txt:
                txt = re.sub(r"^([^:]{2,60}):\s", r"<b>\1:</b> ", txt)
            out.append(Paragraph(txt, S["bullet"], bulletText="\u2022") if m
                       else Paragraph(txt, S["body"]))
            emitted = True
        if not emitted:
            out.append(Paragraph(esc(content), S["body"]))
        return out

    # ── story (begins on page 2; page 1 is the canvas cover) ─────────────────
    story = [PageBreak()]

    toc = TableOfContents()
    toc.dotsMinLevel = 1
    toc.levelStyles = [
        ParagraphStyle("TOC0", fontName="Helvetica-Bold", fontSize=12, textColor=NAVY,
                       leading=18, spaceBefore=9, leftIndent=0),
        ParagraphStyle("TOC1", fontName="Helvetica", fontSize=10, textColor=MUTE,
                       leading=15, spaceBefore=2, leftIndent=18),
    ]
    story += [Paragraph("Table of Contents", S["toc_h"]),
              HRFlowable(width="100%", thickness=1.4, color=GOLD,
                         spaceBefore=4, spaceAfter=10),
              toc, PageBreak()]

    for idx, rtype in enumerate(_present):
        rep = reports[rtype]
        story.append(Paragraph(REPORT_LABELS[rtype], S["group"]))
        story.append(HRFlowable(width="100%", thickness=1.4, color=GOLD,
                                spaceBefore=4, spaceAfter=8))
        if rtype == "monetized":
            _score = str(rep.get("qml_score", _dash))
            _roi = str(rep.get("projected_roi", _dash))
            _c1 = 'QML Score<br/><font size=15 color="#0A1628">' + _score + '%</font>'
            _c2 = 'Projected ROI<br/><font size=15 color="#0A1628">' + _roi + '</font>'
            kpi = Table([[Paragraph(_c1, S["kpi"]), Paragraph(_c2, S["kpi"])]],
                        colWidths=[3.3 * inch, 3.3 * inch])
            kpi.setStyle(TableStyle([
                ("BACKGROUND", (0, 0), (-1, -1), LAV_BG),
                ("BOX", (0, 0), (-1, -1), 1, LAV_BD),
                ("LEFTPADDING", (0, 0), (-1, -1), 14),
                ("TOPPADDING", (0, 0), (-1, -1), 10),
                ("BOTTOMPADDING", (0, 0), (-1, -1), 10),
            ]))
            story += [kpi, Spacer(1, 8)]
        for sec in rep.get("sections", []):
            story.append(Paragraph(esc(sec.get("heading", "")), S["sec"]))
            story += _section_flowables(sec.get("content", ""))
        if idx != len(_present) - 1:
            story.append(PageBreak())

    buf = _io.BytesIO()
    doc = _D3Doc(buf, pagesize=LETTER,
                 leftMargin=0.85 * inch, rightMargin=0.85 * inch,
                 topMargin=1.2 * inch, bottomMargin=0.95 * inch,
                 title="DOMINATE 3AI Intelligence Report")
    doc.multiBuild(story, onFirstPage=_cover, onLaterPages=_content)
    return buf.getvalue()


def send_email(recipient: str, subject: str, body: str, attachment: tuple = None) -> tuple:
    """Send the reports via SMTP. Returns (ok: bool, message: str).

    Provider-agnostic: works with Gmail, Outlook/Microsoft 365, Yahoo, iCloud,
    Zoho, corporate servers, and transactional relays (SendGrid, Brevo, Mailgun).
    It auto-selects the connection type from the port (465 -> SSL, otherwise
    STARTTLS) unless you set `security` explicitly.

    attachment, if given, is (filename, data_bytes, subtype) e.g.
    ("reports.pdf", b"...", "pdf").

    Config — read from .streamlit/secrets.toml:

        [email]
        smtp_server  = "smtp.gmail.com"   # your provider's SMTP host
        smtp_port    = 587                # 587 (STARTTLS) or 465 (SSL)
        sender       = "dominate3ai@gmail.com"  # the From address
        app_password = "ABP+Dominate3ai2026"    # app password / API key / mailbox password
        # username   = "apikey"           # optional: login name if != sender
        # security   = "starttls"         # optional: "starttls" | "ssl" | "none"
        # timeout    = 30                  # optional: seconds
    """
    try:
        cfg = st.secrets["email"]
    except Exception:
        return (False, "Email is not configured. Add an [email] section to "
                       ".streamlit/secrets.toml (see the comments in send_email).")

    try:
        host = str(cfg["smtp_server"]).strip()
        port = int(cfg.get("smtp_port", 587))
        sender = str(cfg["sender"]).strip()
        username = str(cfg.get("username", sender)).strip()   # some relays: login != From
        # Gmail shows app passwords as 4 space-separated groups; users often paste
        # them with the spaces, which makes auth fail. Strip all whitespace.
        password = "".join(str(cfg.get("app_password", "")).split())
        timeout = int(cfg.get("timeout", 30))
        # Connection security: explicit override, else inferred from the port.
        security = str(cfg.get("security", "")).strip().lower()
        if not security:
            security = "ssl" if port == 465 else "starttls"
    except Exception as e:
        return (False, f"Email config is incomplete: {e}")

    try:
        msg = MIMEMultipart()
        msg["From"] = sender
        msg["To"] = recipient
        msg["Subject"] = subject
        msg.attach(MIMEText(body, "plain", "utf-8"))

        if attachment:
            fname, data, subtype = attachment
            part = MIMEApplication(data, _subtype=subtype)
            part.add_header("Content-Disposition", "attachment", filename=fname)
            msg.attach(part)

        if security == "ssl":
            ssl_ctx = ssl.create_default_context()
            server = smtplib.SMTP_SSL(host, port, timeout=timeout, context=ssl_ctx)
        else:
            server = smtplib.SMTP(host, port, timeout=timeout)
            server.ehlo()
            if security in ("starttls", "tls"):
                server.starttls(context=ssl.create_default_context())
                server.ehlo()

        if password:                                   # skip auth only for open relays
            server.login(username, password)
        server.sendmail(sender, recipient, msg.as_string())
        server.quit()
        return (True, f"Reports sent to {recipient}.")
    except Exception as e:
        return (False, f"Could not send email: {e}")


