if "report_data" in st.session_state:
    reports = st.session_state["report_data"]
    report_org = st.session_state.get("report_org", "Organization")

    st.markdown('<div class="sec-lbl">📄 Generated Reports</div>', unsafe_allow_html=True)
    _report_logo = st.session_state.get("report_logo", "")
    _logo_tag = (
        f'<img src="{_report_logo}" style="height:34px;vertical-align:middle;'
        f'margin-left:12px;background:#fff;padding:2px 6px;border-radius:5px;" '
        f'onerror="this.style.display=\'none\'"/>'
        if _report_logo else ""
    )
    st.markdown(
        f'<div class="sec-title">{report_org} — Intelligence Reports{_logo_tag}</div>',
        unsafe_allow_html=True,
    )

    for rtype in ["normal", "advanced", "monetized"]:
        if rtype in reports:
            render_report(reports[rtype], rtype)

    st.markdown("---")
    text_export = build_text_export(reports, report_org)
    pdf_bytes = build_pdf(reports, report_org, st.session_state.get("report_logo", ""))
    base = f"{report_org.replace(' ', '_')}_DOMINATE3AI_{datetime.now().strftime('%Y%m%d')}"

    dl1, dl2 = st.columns(2)
    with dl1:
        if pdf_bytes:
            st.download_button(
                label="⬇ Download PDF",
                data=pdf_bytes,
                file_name=f"{base}.pdf",
                mime="application/pdf",
                use_container_width=True,
                type="primary",
            )
        else:
            st.button("⬇ Download PDF", use_container_width=True, disabled=True)
            st.caption("Install reportlab for PDF export:  pip install reportlab")
    with dl2:
        st.download_button(
            label="⬇ Download .txt",
            data=text_export,
            file_name=f"{base}.txt",
            mime="text/plain",
            use_container_width=True,
        )

    # ── Email the reports (PDF attached when available) ───────────────────────
    st.markdown('<div class="sec-lbl">📧 Email Reports</div>', unsafe_allow_html=True)
    ecol1, ecol2 = st.columns([3, 1])
    with ecol1:
        recipient = st.text_input(
            "Recipient email address",
            placeholder="name@company.com",
            label_visibility="collapsed",
            key="email_recipient",
        )
    with ecol2:
        send_clicked = st.button("✉ Send to Email", use_container_width=True)

    if send_clicked:
        if not recipient or "@" not in recipient:
            st.error("Please enter a valid email address.")
        else:
            subject = f"DOMINATE 3AI Intelligence Reports — {report_org}"
            if pdf_bytes:
                attachment = (f"{base}.pdf", pdf_bytes, "pdf")
                body = (
                    f"Hello,\n\nPlease find attached the DOMINATE 3AI intelligence "
                    f"reports for {report_org}, generated on "
                    f"{datetime.now().strftime('%Y-%m-%d %H:%M')} using a local "
                    f"Ollama model.\n\n— DOMINATE 3AI · ABP Communications LLC"
                )
            else:
                attachment = None
                body = text_export
            with st.spinner("Sending reports..."):
                ok, msg = send_email(recipient, subject, body, attachment)
            if ok:
                st.success(f"✅ {msg}" + (" (PDF attached)" if pdf_bytes else " (text only)"))
            else:
                st.warning(f"⚠ {msg}")


